query:
UPDATE players SET cardType = 'diamond' WHERE overall >= 90;
UPDATE players SET cardType = 'gold'    WHERE overall >= 80 AND overall < 90;
UPDATE players SET cardType = 'silver'  WHERE overall >= 70 AND overall < 80;
UPDATE players SET cardType = 'bronze'  WHERE overall < 70;

SELECT cardType, COUNT(*) as total, MIN(overall) as min_ov, MAX(overall) as max_ov
FROM players GROUP BY cardType ORDER BY max_ov DESC;

